import{_ as t,o as r,c as a,a4 as n}from"./chunks/framework.DQHfP2Tl.js";const p=JSON.parse('{"title":"Security Architecture","description":"","frontmatter":{},"headers":[],"relativePath":"reference/architecture/security.md","filePath":"reference/architecture/security.md"}'),i={name:"reference/architecture/security.md"};function o(s,e,d,c,l,h){return r(),a("div",null,[...e[0]||(e[0]=[n('<h1 id="security-architecture" tabindex="-1">Security Architecture <a class="header-anchor" href="#security-architecture" aria-label="Permalink to &quot;Security Architecture&quot;">​</a></h1><blockquote><p><strong>Last Updated</strong>: 2026-06-28 <strong>See also</strong>: the project&#39;s security coding standards (CLAUDE.md) for implementation-level rules.</p></blockquote><h2 id="threat-model" tabindex="-1">Threat Model <a class="header-anchor" href="#threat-model" aria-label="Permalink to &quot;Threat Model&quot;">​</a></h2><p><code>@jsvision/core</code> is a client-side terminal library with <strong>no network surface, no persistence, and no telemetry</strong>. The assets it protects are the integrity of the terminal session and the host process. The principal threats are untrusted bytes — text drawn to the screen and bytes read back from the terminal — being interpreted as control sequences.</p><table tabindex="0"><thead><tr><th>Asset</th><th>Threat</th><th>Mitigation</th><th>Status</th></tr></thead><tbody><tr><td>Terminal session integrity</td><td>Untrusted text injects escape sequences at render time</td><td>Canonical <code>sanitize</code> boundary strips control bytes before they become cells</td><td>✅ Implemented</td></tr><tr><td>Detection robustness</td><td>A malicious/slow terminal floods or stalls the capability query</td><td>Bounded response buffer (<code>RESPONSE_BUFFER_CAP</code>) + single bounded <code>timeoutMs</code></td><td>✅ Implemented</td></tr><tr><td>Process stability</td><td>Bad cell data / malformed colour crashes the render loop</td><td>Render-path encoder degrades crash-safe; typed <code>TuiError</code> model</td><td>✅ Implemented</td></tr><tr><td>Secret leakage</td><td>Secrets/PII written to logs or capability dumps</td><td><code>redactEvent</code> / screen-safe logger redact before output; nothing logged by default</td><td>✅ Implemented</td></tr><tr><td>Supply chain</td><td>A malicious/native transitive dependency</td><td>Zero runtime dependencies; <code>check:deps</code> guard; <code>npm audit</code> in CI</td><td>✅ Implemented</td></tr></tbody></table><h2 id="authentication-authorization" tabindex="-1">Authentication &amp; Authorization <a class="header-anchor" href="#authentication-authorization" aria-label="Permalink to &quot;Authentication &amp; Authorization&quot;">​</a></h2><p>Not applicable — the library has no users, accounts, sessions, or network endpoints. It runs entirely in the host process with the privileges of the invoking program.</p><h2 id="data-protection" tabindex="-1">Data Protection <a class="header-anchor" href="#data-protection" aria-label="Permalink to &quot;Data Protection&quot;">​</a></h2><ul><li><strong>In transit / at rest</strong>: none — the library neither transmits nor stores data.</li><li><strong>PII handling</strong>: the library handles no PII. The logger and <code>redactEvent</code> actively strip anything that looks like a secret/PII before any sink write.</li><li><strong>Secrets</strong>: none are read, embedded, or logged.</li></ul><h2 id="input-validation-injection-prevention" tabindex="-1">Input Validation &amp; Injection Prevention <a class="header-anchor" href="#input-validation-injection-prevention" aria-label="Permalink to &quot;Input Validation &amp; Injection Prevention&quot;">​</a></h2><p>The <strong>canonical injection boundary</strong> is <code>sanitize</code> (see <a href="/jsvision/pr-preview/pr-138/reference/decisions/ADR-005-sanitize-boundary.html">ADR-005</a>). All text that becomes screen cells passes through it (e.g. <code>ScreenBuffer.text</code>), so control bytes in untrusted input can never reach the terminal as live escape sequences at serialize time.</p><p>Capability-query responses are treated as <strong>untrusted data</strong>: only exact, fully-terminated grammar matches become capabilities; the response buffer is length-bounded and discarded on overflow; everything else is forwarded as passthrough input, never executed.</p><h2 id="infrastructure-supply-chain-security" tabindex="-1">Infrastructure &amp; Supply-Chain Security <a class="header-anchor" href="#infrastructure-supply-chain-security" aria-label="Permalink to &quot;Infrastructure &amp; Supply-Chain Security&quot;">​</a></h2><ul><li><strong>Zero runtime dependencies</strong> (<a href="/jsvision/pr-preview/pr-138/reference/decisions/ADR-001-esm-zero-dependency.html">ADR-001</a>) — the runtime attack surface is the Node standard library only. Enforced by <code>npm run check:deps</code> (fails on any native runtime dep).</li><li><strong>Dependency audit</strong> — <code>npm audit --audit-level=high</code> runs in CI; the dev dependency surface is kept minimal (the RD-10 tree-shake check uses <code>esbuild</code>, a dev-only prebuilt binary with no compile step).</li><li><strong>Provenance</strong> — npm publish provenance is <strong>deferred</strong> until the first real release with CI OIDC (RD-10 DEF-1).</li></ul>',14)])])}const m=t(i,[["render",o]]);export{p as __pageData,m as default};
